#include <iostream>
#include <string>

using namespace std;

class Solution {
public:
    bool solve(const string& s) {
        s = s.substr(0, s.length() - 1);
        s = s.substr(1);
        return s == "";
    }
};

int main() {
    Solution obj;
    int n;
    cin >> n;
    cin.ignore();
    while (n-- > 0) {
        string s;
        getline(cin, s);
        s = s.substr(0, s.length() - 1);
        cout << (obj.solve(s) ? "YES" : "NO") << endl;
    }
    return 0;
}
